#!/bin/bash
set -e
echo "📱 Fix responsive biblio..."
cd "$(git rev-parse --show-toplevel)"
python3 - << 'INNER'
import base64, os
open("src/app/library/page.tsx", "wb").write(base64.b64decode(""))
